function headingName(deg){const d=((deg%360)+360)%360;if(d<11.25||d>=348.75)return'East';if(d<78.75)return`Diagonal ${d.toFixed(1)}°`;if(d<101.25)return'South';if(d<168.75)return`Diagonal ${d.toFixed(1)}°`;if(d<191.25)return'West';if(d<258.75)return`Diagonal ${d.toFixed(1)}°`;if(d<281.25)return'North';return`Diagonal ${d.toFixed(1)}°`}
function guideRadius(){return 95/ensureSketch().viewport.scale}
function guideHitRadius(){return 34/ensureSketch().viewport.scale}
function guidePointsFor(fp){if(!fp||fp.closed||!fp.points.length)return[];const c=fp.points[fp.points.length-1],r=guideRadius();return[0,45,90,135,180,225,270,315].map(heading=>{const a=heading*Math.PI/180;return{heading,x:c.x+Math.cos(a)*r,y:c.y+Math.sin(a)*r}})}
