  $('#cutoutTitle').textContent=item?`Edit ${item.label||'cut-out'}`:(subtype==='garage'?'Garage cut-out':'Open to below');
  $('#cutoutLength').value=item?Number(item.length||0).toFixed(2).replace(/\.00$/,''):'';
  $('#cutoutWidth').value=item?Number(item.width||0).toFixed(2).replace(/\.00$/,''):'';
  let q='SE';if(item&&item.points&&item.points[1]){const b=item.points[1];q=(b.x>=anchor.x?'E':'W')+(b.y>=anchor.y?'S':'N')}
