  if(!sketchAuxStart){sketchAuxStart={x:p.x,y:p.y};drawSketch();return true}
  const a=sketchAuxStart,b={x:p.x,y:p.y};sketchAuxStart=null;if(Math.hypot(b.x-a.x,b.y-a.y)<8){drawSketch();return true}
  pushSketchHistory();activeFloor().items.push({id:uid('interior'),kind:'interiorLine',points:[a,b]});save();drawSketch();updateSketchSummary();return true
