function openClosureAssist(g){const fp=activeFootprint(),last=fp.points[fp.points.length-1];pendingWall={footprintId:fp.id,heading:Math.atan2(g.y-last.y,g.x-last.x)*180/Math.PI,closureAssist:g};$('#closureDirection').textContent=g.label;$('#closureDistance').textContent=`${g.length.toFixed(2)} ft calculated`;$('#closureDialog').hidden=false}
