function zoomAt(clientX,clientY,mult){const s=ensureSketch(),r=$('#sketchStage').getBoundingClientRect(),old=s.viewport.scale,ns=Math.max(.35,Math.min(5,old*mult)),wx=(clientX-r.left-s.viewport.x)/old,wy=(clientY-r.top-s.viewport.y)/old;s.viewport.scale=ns;s.viewport.x=clientX-r.left-wx*ns;s.viewport.y=clientY-r.top-wy*ns;save();applySketchTransform()}
